function CTbl(p){var sorted=p.sortMode==='avg'?[].concat(p.data).sort(function(a,b){return(b.Avg||0)-(a.Avg||0)}):p.data;var mc=Math.max.apply(null,sorted.map(function(d){return d.Films}).concat([1]));return <div className="space-y-1">{sorted.map(function(d,i){var ac=p.sel===d.name;return <div key={i} onClick={function(){p.onSel(ac?null:d.name)}} title={d.tip||''} className={'flex items-center gap-2 cursor-pointer rounded px-1 py-0.5 '+(ac?'bg-gray-800 ring-1 ring-emerald-500':'hover:bg-gray-800/50')}><div className="w-28 text-xs text-gray-400 text-right truncate" title={d.name}>{d.name}</div><div className="flex-1 h-7 bg-gray-800 rounded overflow-hidden flex items-center"><div className="h-full rounded flex items-center px-2" style={{width:Math.max((d.Films/mc)*100,8)+'%',minWidth:32,backgroundColor:rC(d.Avg)}}><span className="text-xs font-bold" style={{color:'#111'}}>{d.Films}</span></div></div><div className="w-14 text-xs text-right font-mono" style={{color:rC(d.Avg)}}>{d.Avg>0?d.Avg.toFixed(1)+'★':'—'}</div></div>})}</div>}
