      {tagSelCount>0&&<div className="flex items-center gap-2 bg-gray-900 rounded-lg px-3 py-2 border border-gray-700"><span className="text-xs text-gray-300">{tagSelCount} sel</span><select className="bg-gray-800 border border-gray-700 rounded text-xs text-gray-300 px-1 py-0.5" value={bulkCat} onChange={function(e){sBulkCat(e.target.value)}}><option value="">Assign...</option>{CATS.map(function(c){return <option key={c} value={c}>{CI[c].l}</option>})}</select><button onClick={doBulkTag} disabled={!bulkCat} className="text-xs bg-emerald-700 disabled:bg-gray-700 text-white px-2 py-0.5 rounded">Apply</button><button onClick={function(){sTagSel({})}} className="text-xs text-gray-500">Clear</button></div>}
      <button onClick={function(){var n={};tagFiltered.forEach(function(t){n[t]=true});sTagSel(n)}} className="text-xs bg-gray-800 text-gray-400 px-2 py-1 rounded">Select visible</button>
